#include <nds.h>

int main(void) {
    consoleDemoInit();
    while(1) {
        scanKeys();
        if (keysHeld() & KEY_TOUCH) {
            touchPosition touch;
            touchRead(&touch);
            iprintf("Touched: %d, %d\n",
                    touch.px, touch.py);
        }
        swiWaitForVBlank();
    }
}

